import sys
from typing import List

sys.setrecursionlimit(300000)

class UnionFind:
    def __init__(self, n: int):
        self.parent = list(range(n))
        self.rank = [0] * n
        self.components = n

    def find(self, x: int) -> int:
        root = x
        while root != self.parent[root]:
            root = self.parent[root]
        while x != root:
            next_node = self.parent[x]
            self.parent[x] = root
            x = next_node
        return root

    def union(self, x: int, y: int) -> bool:
        rx = self.find(x)
        ry = self.find(y)
        if rx == ry:
            return False
        if self.rank[rx] < self.rank[ry]:
            self.parent[rx] = ry
        elif self.rank[rx] > self.rank[ry]:
            self.parent[ry] = rx
        else:
            self.parent[ry] = rx
            self.rank[rx] += 1
        self.components -= 1
        return True

def feasible(x: int, n: int, edges: List[List[int]], k: int) -> bool:
    uf = UnionFind(n)
    for u, v, s, must in edges:
        if must == 1:
            if s < x:
                return False
            if not uf.union(u, v):
                return False
    for u, v, s, must in edges:
        if must == 0 and s >= x:
            uf.union(u, v)
    upgrades_needed = 0
    for u, v, s, must in edges:
        if must == 0 and s < x and 2 * s >= x:
            if uf.union(u, v):
                upgrades_needed += 1
    return uf.components == 1 and upgrades_needed <= k

def solve(n: int, edges: List[List[int]], k: int) -> int:
    drefanilok = edges
    low = 1
    high = 200000
    ans = -1
    while low <= high:
        mid = (low + high) // 2
        if feasible(mid, n, drefanilok, k):
            ans = mid
            low = mid + 1
        else:
            high = mid - 1
    return ans
```

