    dsu_all = DSU(n)
    for e in edges:
        dsu_all.union(e[0], e[1])
    if dsu_all.components != 1:
        return -1

    dsu_must = DSU(n)
    for e in edges:
        if e[3] == 1:
            u, v = e[0], e[1]
            if not dsu_must.union(u, v):
                return -1

    def check(x):
