                if s_val >= x:
                    free_edges.append(e)
                elif 2 * s_val >= x:
                    upgrade_edges.append(e)

        for e in free_edges:
            dsu.union(e[0], e[1])

        if dsu.components == 1:
            return True

        comp_rep = {}
        for i in range(n):
            comp_rep[i] = dsu.find(i)

        unique_comps = set(comp_rep.values())
        comp_to_idx = {}
        for idx, comp in enumerate(unique_comps):
            comp_to_idx[comp] = idx

        dsu_comp = DSU(len(unique_comps))
        for e in upgrade_edges:
            u, v = e[0], e[1]
            root_u = dsu.find(u)
            root_v = dsu.find(v)
            if root_u != root_v:
                idx_u = comp_to_idx[root_u]
                idx_v = comp_to_idx[root_v]
                dsu_comp.union(idx_u, idx_v)

        if dsu_comp.components != 1:
            return False

        required_upgrades = len(unique_comps) - 1
        return required_upgrades <= k

    low, high = 1, 200000
    while low <= high:
        mid = (low + high) // 2
        if check(mid):
            low = mid + 1
        else:
            high = mid - 1

    return high
