            high = mid - 1

    return ans

def check(n, edges, k, x):
    parent = list(range(n))
    rank = [0] * n
    comps = n

    def find(i):
        if parent[i] != i:
            parent[i] = find(parent[i])
        return parent[i]

    def union(u, v):
        nonlocal comps
        ru = find(u)
        rv = find(v)
        if ru == rv:
            return False
        if rank[ru] < rank[rv]:
            parent[ru] = rv
        elif rank[ru] > rank[rv]:
            parent[rv] = ru
        else:
            parent[rv] = ru
            rank[ru] += 1
        comps -= 1
        return True

    for u, v, s, must in edges:
        if must == 1:
            if s < x:
                return False
            else:
                if find(u) == find(v):
                    return False
                else:
                    union(u, v)

    for u, v, s, must in edges:
        if comps == 1:
            break
        if must == 0 and s >= x:
            if find(u) != find(v):
                union(u, v)

    upgrades = 0
    for u, v, s, must in edges:
        if comps == 1:
            break
        if must == 0 and s < x and 2 * s >= x:
            if find(u) != find(v):
                union(u, v)
                upgrades += 1

    if comps != 1:
        return False
    if upgrades <= k:
        return True
    else:
        return False
```

### Explanation
1. **Binary Search Setup**: The `solve` function initializes binary search bounds (`low` and `high`) to find the maximum stability. The search checks each candidate `mid` value using the `check` function.
2. **Check Function**: For each candidate `x`:
   - **DSU Initialization**: The DSU structures (`parent`, `rank`, and `comps`) track connected components.
   - **Must Edges Processing**: Must edges are processed first. Any must edge with strength < `x` or forming a cycle invalidates the candidate.
   - **Optional Edges Without Upgrade**: Optional edges with strength ≥ `x` are added to connect components without using upgrades.
   - **Optional Edges With Upgrade**: Remaining optional edges that can meet `x` after an upgrade are added if necessary, counting each upgrade used.
3. **Feasibility Check**: After processing edges, if the graph is connected (`comps == 1`) and upgrades used ≤ `k`, the candidate `x` is feasible, and binary search adjusts bounds to find a higher feasible stability; otherwise, it checks lower values.

This approach efficiently narrows down the maximum achievable stability using binary search and ensures the solution meets the constraints using DSU for connectivity checks.
